import{c as a,Q as e,j as s,m as o}from"./chunks/framework.rlpw0eGz.js";const g=JSON.parse('{"title":"技能","description":"","frontmatter":{},"headers":[],"relativePath":"zh/getting-started/skills.md","filePath":"zh/getting-started/skills.md","lastUpdated":1777012567000}'),i={name:"zh/getting-started/skills.md"};function d(l,t,r,n,h,c){return e(),s("div",null,[...t[0]||(t[0]=[o(`<h1 id="技能" tabindex="-1">技能 <a class="header-anchor" href="#技能" aria-label="Permalink to &quot;技能&quot;">​</a></h1><p><strong>技能</strong>是可复用的提示模块，用来改机器人的语气、行为方式、工具使用习惯。在机器人的 <strong>Skills</strong> tab 里管；可手写，也可从 <a href="/zh/getting-started/supermarket.html">超市</a> 装。</p><hr><h2 id="长什么样" tabindex="-1">长什么样 <a class="header-anchor" href="#长什么样" aria-label="Permalink to &quot;长什么样&quot;">​</a></h2><p>就是带 YAML 头的 <code>SKILL.md</code>，至少要有稳定的 <code>name</code> 和短 <code>description</code>。</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">coder-skill</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">Enables advanced coding workflows and tool usage.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Coder Skill</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">你写清楚代码、说明取舍，该用文件/命令工具时就用。</span></span></code></pre></div><p>建议：</p><ul><li>名字用简单 ASCII，如 <code>coder-skill</code>、<code>research</code>，别带空格；Memoh 会拿它当目录名。</li><li>正文就是真正要注入到运行时的说明。</li></ul><hr><h2 id="从哪来" tabindex="-1">从哪来 <a class="header-anchor" href="#从哪来" aria-label="Permalink to &quot;从哪来&quot;">​</a></h2><p>分 <strong>托管</strong> 和 <strong>发现</strong>：</p><ul><li><strong>托管</strong>：你在 Memoh 里建、改、从超市装的，放在 <code>/data/skills/&lt;name&gt;/SKILL.md</code>。</li><li><strong>发现</strong>：容器里旧目录、导入镜像里带来的兼容路径。</li></ul><p>Memoh 按顺序扫这些根：</p><table tabindex="0"><thead><tr><th>类型</th><th>根路径</th></tr></thead><tbody><tr><td>托管</td><td><code>/data/skills/</code></td></tr><tr><td>旧版发现</td><td><code>/data/.skills/</code></td></tr><tr><td>兼容</td><td><code>/data/.agents/skills/</code></td></tr><tr><td>兼容</td><td><code>/root/.agents/skills/</code></td></tr></tbody></table><p>每个根下可以直接放 <code>SKILL.md</code>，或子目录如 <code>/data/skills/coder-skill/SKILL.md</code>。</p><p><strong>同名</strong>技能可能多份来源，会进入不同状态（见下）。</p><hr><h2 id="状态" tabindex="-1">状态 <a class="header-anchor" href="#状态" aria-label="Permalink to &quot;状态&quot;">​</a></h2><p>每个来源会标：</p><table tabindex="0"><thead><tr><th>状态</th><th>含义</th></tr></thead><tbody><tr><td><code>effective</code></td><td>这个名字当前<strong>真在用</strong>的这一份</td></tr><tr><td><code>shadowed</code></td><td>同名有别的来源优先了</td></tr><tr><td><code>disabled</code></td><td>这一份被关掉，不用</td></tr></tbody></table><p>记死一点：<strong>技能名是身份</strong>。多个 <code>coder-skill</code> 只能有一个 <code>effective</code>。</p><h3 id="常见情况" tabindex="-1">常见情况 <a class="header-anchor" href="#常见情况" aria-label="Permalink to &quot;常见情况&quot;">​</a></h3><ul><li>刚在 Memoh 里建的多半是托管 + <code>effective</code>。</li><li>老目录里有一份时，可能先由它 <code>effective</code>，直到你装了托管同名。</li><li>把发现的那份 <strong>Adopt</strong> 成托管后，通常托管变 <code>effective</code>，旧来源变 <code>shadowed</code>。</li><li>关掉 <code>effective</code> 那一份，同名里下一位可能顶上来。</li></ul><hr><h2 id="在界面里" tabindex="-1">在界面里 <a class="header-anchor" href="#在界面里" aria-label="Permalink to &quot;在界面里&quot;">​</a></h2><h3 id="添加" tabindex="-1">添加 <a class="header-anchor" href="#添加" aria-label="Permalink to &quot;添加&quot;">​</a></h3><p><strong>Add Skill</strong> → 在编辑器里写 raw Markdown → 保存，写到托管目录。</p><h3 id="编辑" tabindex="-1">编辑 <a class="header-anchor" href="#编辑" aria-label="Permalink to &quot;编辑&quot;">​</a></h3><p><strong>Edit</strong> 改 <code>SKILL.md</code>；自己托管的改起来最直接。</p><h3 id="删除" tabindex="-1">删除 <a class="header-anchor" href="#删除" aria-label="Permalink to &quot;删除&quot;">​</a></h3><p><strong>Delete</strong> 会去掉这份托管目录；若还有发现来源，可能那份又变成 <code>effective</code>。</p><h3 id="禁用-启用" tabindex="-1">禁用 / 启用 <a class="header-anchor" href="#禁用-启用" aria-label="Permalink to &quot;禁用 / 启用&quot;">​</a></h3><p><strong>Disable</strong> 关某一条来源不删；<strong>Enable</strong> 再开。适合试回退、暂时不用某套提示。</p><h3 id="adopt" tabindex="-1">Adopt <a class="header-anchor" href="#adopt" aria-label="Permalink to &quot;Adopt&quot;">​</a></h3><p>把<strong>发现</strong>来源复制进托管目录，方便你长期用界面改。已有托管同名时不能 Adopt。</p><hr><h2 id="运行时" tabindex="-1">运行时 <a class="header-anchor" href="#运行时" aria-label="Permalink to &quot;运行时&quot;">​</a></h2><p>只有 <strong>effective</strong> 会进当前机器人提示。</p><ul><li><code>shadowed</code> 能看、不进提示</li><li><code>disabled</code> 当不存在</li><li>活跃会话的 <strong>状态区</strong> 也会显示这条路上用过哪些技能</li></ul><hr><h2 id="超市和导入" tabindex="-1">超市和导入 <a class="header-anchor" href="#超市和导入" aria-label="Permalink to &quot;超市和导入&quot;">​</a></h2><ul><li><strong>超市安装</strong>：下好的技能进托管目录，和手写一样。</li><li><strong>老环境/导入</strong>：可能只出现在发现路径，需要就 <strong>Adopt</strong>。</li></ul><hr><h2 id="建议工作流" tabindex="-1">建议工作流 <a class="header-anchor" href="#建议工作流" aria-label="Permalink to &quot;建议工作流&quot;">​</a></h2><ol><li>先少而精，名字和描述写清楚。</li><li>不确定删不删时先 <strong>Disable</strong>。</li><li>要长期留用的发现项用 <strong>Adopt</strong>。</li><li>能复用就从 <a href="/zh/getting-started/supermarket.html">超市</a> 装，少复制粘贴多份。</li></ol>`,45)])])}const k=a(i,[["render",d]]);export{g as __pageData,k as default};
